    16→package org.pkl.parser;
    17→
    18→import java.util.ArrayDeque;
    19→import java.util.Deque;
    20→import org.pkl.parser.util.ErrorMessages;
    21→
    22→public class Lexer {
    23→
    24→  private final char[] source;
    25→  private final int size;
    26→  protected int cursor = 0;
    27→  protected int sCursor = 0;
    28→  private char lookahead;
    29→  private State state = State.DEFAULT;
    30→  private final Deque<InterpolationScope> interpolationStack = new ArrayDeque<>();
    31→  private boolean stringEnded = false;
    32→  private boolean isEscape = false;
    33→  // how many newlines exist between two subsequent tokens
    34→  protected int newLinesBetween = 0;
    35→
    36→  private static final char EOF = Short.MAX_VALUE;
    37→
    38→  public Lexer(String input) {
    39→    source = input.toCharArray();
    40→    size = source.length;
    41→    if (size > 0) {
    42→      lookahead = source[cursor];
    43→    } else {
    44→      lookahead = EOF;
    45→    }
    46→  }
    47→
    48→  // The span of the last lexed token
    49→  public Span span() {
    50→    return new Span(sCursor, cursor - sCursor);
    51→  }
    52→
    53→  // The text of the last lexed token
    54→  public String text() {
    55→    return new String(source, sCursor, cursor - sCursor);
    56→  }
    57→
    58→  public char[] getSource() {
    59→    return source;
    60→  }
    61→
    62→  public String textFor(int offset, int size) {
    63→    return new String(source, offset, size);
    64→  }
    65→
    66→  public Token next() {
    67→    sCursor = cursor;
    68→    newLinesBetween = 0;
    69→    return switch (state) {
    70→      case DEFAULT -> nextDefault();
    71→      case STRING -> nextString();
    72→    };
    73→  }
    74→
    75→  private Token nextDefault() {
    76→    var ch = nextChar();
    77→    // ignore spaces
    78→    while (ch == ' ' || ch == '\n' || ch == '\t' || ch == '\f' || ch == '\r') {
    79→      sCursor = cursor;
    80→      if (ch == '\n') {
    81→        newLinesBetween++;
    82→      }
    83→      ch = nextChar();
    84→    }
    85→    return switch (ch) {
    86→      case EOF -> {
    87→        // when EOF is reached we overshot the span
    88→        cursor--;
    89→        yield Token.EOF;
    90→      }
    91→      case ';' -> Token.SEMICOLON;
    92→      case '(' -> {
    93→        var scope = interpolationStack.peek();
    94→        if (scope != null) {
    95→          scope.parens++;
    96→        }
    97→        yield Token.LPAREN;
    98→      }
    99→      case ')' -> {
   100→        var scope = interpolationStack.peek();
   101→        if (scope != null) {
   102→          scope.parens--;
   103→          if (scope.parens <= 0) {
   104→            // interpolation is over. Back to string
   105→            state = State.STRING;
   106→          }
   107→        }
   108→        yield Token.RPAREN;
   109→      }
   110→      case '{' -> Token.LBRACE;
   111→      case '}' -> Token.RBRACE;
   112→      case ',' -> Token.COMMA;
   113→      case '@' -> Token.AT;
   114→      case ':' -> Token.COLON;
   115→      case '+' -> Token.PLUS;
   116→      case '%' -> Token.MOD;
   117→      case '[' -> {
   118→        if (lookahead == '[') {
   119→          nextChar();
   120→          yield Token.LPRED;
   121→        } else yield Token.LBRACK;
   122→      }
   123→      case ']' -> Token.RBRACK;
   124→      case '=' -> {
   125→        if (lookahead == '=') {
   126→          nextChar();
   127→          yield Token.EQUAL;
   128→        } else yield Token.ASSIGN;
   129→      }
   130→      case '>' -> {
   131→        if (lookahead == '=') {
   132→          nextChar();
   133→          yield Token.GTE;
   134→        } else yield Token.GT;
   135→      }
   136→      case '<' -> {
   137→        if (lookahead == '=') {
   138→          nextChar();
   139→          yield Token.LTE;
   140→        } else yield Token.LT;
   141→      }
   142→      case '-' -> {
   143→        if (lookahead == '>') {
   144→          nextChar();
   145→          yield Token.ARROW;
   146→        } else yield Token.MINUS;
   147→      }
   148→      case '!' -> {
   149→        if (lookahead == '!') {
   150→          nextChar();
   151→          yield Token.NON_NULL;
   152→        } else if (lookahead == '=') {
   153→          nextChar();
   154→          yield Token.NOT_EQUAL;
   155→        } else yield Token.NOT;
   156→      }
   157→      case '?' -> {
   158→        if (lookahead == '.') {
   159→          nextChar();
   160→          yield Token.QDOT;
   161→        } else if (lookahead == '?') {
   162→          nextChar();
   163→          yield Token.COALESCE;
   164→        } else yield Token.QUESTION;
   165→      }
   166→      case '&' -> {
   167→        if (lookahead == '&') {
   168→          nextChar();
   169→          yield Token.AND;
   170→        } else {
   171→          throw unexpectedChar(ch, "&&");
   172→        }
   173→      }
   174→      case '|' -> {
   175→        if (lookahead == '>') {
   176→          nextChar();
   177→          yield Token.PIPE;
   178→        } else if (lookahead == '|') {
   179→          nextChar();
   180→          yield Token.OR;
   181→        } else {
   182→          yield Token.UNION;
   183→        }
   184→      }
   185→      case '*' -> {
   186→        if (lookahead == '*') {
   187→          nextChar();
   188→          yield Token.POW;
   189→        } else yield Token.STAR;
   190→      }
   191→      case '~' -> {
   192→        if (lookahead == '/') {
   193→          nextChar();
   194→          yield Token.INT_DIV;
   195→        } else {
   196→          throw unexpectedChar(ch, "~/");
   197→        }
   198→      }
   199→      case '.' -> {
   200→        if (lookahead == '.') {
   201→          nextChar();
   202→          if (lookahead == '.') {
   203→            nextChar();
   204→            if (lookahead == '?') {
   205→              nextChar();
   206→              yield Token.QSPREAD;
   207→            } else {
   208→              yield Token.SPREAD;
   209→            }
   210→          } else {
   211→            throw unexpectedChar("..", ".", "...", "...?");
   212→          }
   213→        } else if (lookahead >= 48 && lookahead <= 57) {
   214→          yield lexNumber(ch);
   215→        } else {
   216→          yield Token.DOT;
   217→        }
   218→      }
   219→      case '`' -> {
   220→        lexQuotedIdentifier();
   221→        yield Token.IDENTIFIER;
   222→      }
   223→      case '/' -> lexSlash();
   224→      case '"' -> lexStringStart(0);
   225→      case '#' -> {
   226→        if (lookahead == '!') {
   227→          yield lexShebang();
   228→        } else {
   229→          yield lexStringStartPounds();
   230→        }
   231→      }
   232→      default -> {
   233→        if (Character.isDigit(ch)) {
   234→          yield lexNumber(ch);
   235→        } else if (isIdentifierStart(ch)) {
   236→          yield lexIdentifier();
   237→        } else throw lexError(ErrorMessages.create("invalidCharacter", ch), cursor - 1, 1);
   238→      }
   239→    };
   240→  }
