   421→  private Token lexEscape() {
   422→    if (lookahead == EOF) throw unexpectedEndOfFile();
   423→    var ch = nextChar();
   424→    return switch (ch) {
   425→      case 'n' -> Token.STRING_ESCAPE_NEWLINE;
   426→      case '"' -> Token.STRING_ESCAPE_QUOTE;
   427→      case '\\' -> Token.STRING_ESCAPE_BACKSLASH;
   428→      case 't' -> Token.STRING_ESCAPE_TAB;
   429→      case 'r' -> Token.STRING_ESCAPE_RETURN;
   430→      case '(' -> {
   431→        var scope = interpolationStack.getFirst();
   432→        scope.parens++;
   433→        state = State.DEFAULT;
   434→        yield Token.INTERPOLATION_START;
   435→      }
   436→      case 'u' -> lexUnicodeEscape();
   437→      default ->
   438→          throw lexError(
   439→              ErrorMessages.create("invalidCharacterEscapeSequence", "\\" + ch, "\\"),
   440→              cursor - 2,
   441→              2);
   442→    };
   443→  }
   444→
   445→  private Token lexUnicodeEscape() {
   446→    if (lookahead != '{') {
   447→      throw unexpectedChar(lookahead, "{");
   448→    }
   449→    do {
   450→      nextChar();
   451→    } while (lookahead != '}' && lookahead != EOF && Character.isLetterOrDigit(lookahead));
   452→    if (lookahead == '}') {
   453→      // consume the close bracket
   454→      nextChar();
   455→    } else {
   456→      throw lexError(ErrorMessages.create("unterminatedUnicodeEscapeSequence", text()), span());
   457→    }
   458→    return Token.STRING_ESCAPE_UNICODE;
   459→  }
   460→
   461→  private Token lexIdentifier() {
   462→    while (isIdentifierPart(lookahead)) {
   463→      nextChar();
   464→    }
   465→
   466→    var identifierStr = text();
   467→    var identifier = getKeywordOrIdentifier(identifierStr);
   468→    return switch (identifier) {
   469→      case IMPORT -> {
   470→        if (lookahead == '*') {
   471→          nextChar();
   472→          yield Token.IMPORT_STAR;
   473→        } else yield Token.IMPORT;
   474→      }
   475→      case READ ->
   476→          switch (lookahead) {
   477→            case '*' -> {
   478→              nextChar();
   479→              yield Token.READ_STAR;
   480→            }
   481→            case '?' -> {
   482→              nextChar();
   483→              yield Token.READ_QUESTION;
   484→            }
   485→            default -> Token.READ;
   486→          };
   487→      default -> identifier;
   488→    };
   489→  }
   490→
   491→  private void lexQuotedIdentifier() {
   492→    while (lookahead != '`' && lookahead != '\n' && lookahead != '\r') {
   493→      nextChar();
   494→    }
   495→    if (lookahead == '`') {
   496→      nextChar();
   497→    } else {
   498→      throw unexpectedChar(lookahead, "backquote");
   499→    }
   500→  }
   501→
   502→  private Token lexNumber(char start) {
   503→    if (start == '0') {
   504→      if (lookahead == 'x' || lookahead == 'X') {
   505→        nextChar();
   506→        lexHexNumber();
   507→        return Token.HEX;
   508→      }
   509→      if (lookahead == 'b' || lookahead == 'B') {
   510→        nextChar();
   511→        lexBinNumber();
   512→        return Token.BIN;
   513→      }
   514→      if (lookahead == 'o' || lookahead == 'O') {
   515→        nextChar();
   516→        lexOctNumber();
   517→        return Token.OCT;
   518→      }
   519→      if (lookahead == 'e' || lookahead == 'E') {
   520→        nextChar();
   521→        lexExponent();
   522→        return Token.FLOAT;
   523→      }
   524→    } else if (start == '.') {
   525→      lexDotNumber();
   526→      return Token.FLOAT;
   527→    }
   528→
   529→    while ((lookahead >= 48 && lookahead <= 57) || lookahead == '_') {
   530→      nextChar();
   531→    }
   532→
   533→    if (lookahead == 'e' || lookahead == 'E') {
   534→      nextChar();
   535→      lexExponent();
   536→      return Token.FLOAT;
   537→    } else if (lookahead == '.') {
   538→      nextChar();
   539→      if (lookahead == '_') {
   540→        throw lexError("invalidSeparatorPosition");
   541→      }
   542→      if (lookahead < 48 || lookahead > 57) {
   543→        backup();
   544→        return Token.INT;
   545→      }
   546→      lexDotNumber();
   547→      return Token.FLOAT;
   548→    }
   549→    return Token.INT;
   550→  }
   551→
   552→  private Token lexSlash() {
   553→    switch (lookahead) {
   554→      case '/':
   555→        {
   556→          nextChar();
   557→          var token = lookahead == '/' ? Token.DOC_COMMENT : Token.LINE_COMMENT;
   558→          while (lookahead != '\n' && lookahead != '\r' && lookahead != EOF) {
   559→            nextChar();
   560→          }
   561→          return token;
   562→        }
   563→      case '*':
   564→        {
   565→          nextChar();
   566→          lexBlockComment();
   567→          return Token.BLOCK_COMMENT;
   568→        }
   569→      default:
   570→        return Token.DIV;
   571→    }
   572→  }
   573→
   574→  private void lexBlockComment() {
   575→    if (lookahead == EOF) throw unexpectedEndOfFile();
   576→    var prev = nextChar();
   577→    while (lookahead != EOF) {
   578→      if (prev == '*' && lookahead == '/') {
   579→        nextChar();
   580→        break;
   581→      }
   582→      prev = nextChar();
   583→    }
   584→    if (lookahead == EOF) throw unexpectedEndOfFile();
   585→  }
   586→
   587→  private void lexHexNumber() {
   588→    if (lookahead == '_') {
   589→      throw lexError("invalidSeparatorPosition");
   590→    }
   591→    if (!isHex(lookahead)) {
   592→      throw unexpectedChar(lookahead, "hexadecimal number");
   593→    }
   594→    while (isHex(lookahead) || lookahead == '_') {
   595→      nextChar();
   596→    }
   597→  }
   598→
   599→  private void lexBinNumber() {
   600→    if (lookahead == '_') {
   601→      throw lexError("invalidSeparatorPosition");
   602→    }
   603→    if (!(lookahead == '0' || lookahead == '1')) {
   604→      throw unexpectedChar(lookahead, "binary number");
   605→    }
   606→    while (lookahead == '0' || lookahead == '1' || lookahead == '_') {
   607→      nextChar();
   608→    }
   609→  }
   610→
   611→  private void lexOctNumber() {
   612→    if (lookahead == '_') {
   613→      throw lexError("invalidSeparatorPosition");
   614→    }
   615→    var ch = (int) lookahead;
   616→    if (!(ch >= 48 && ch <= 55)) {
   617→      throw unexpectedChar((char) ch, "octal number");
   618→    }
   619→    while ((ch >= 48 && ch <= 55) || ch == '_') {
   620→      nextChar();
   621→      ch = lookahead;
   622→    }
   623→  }
   624→
   625→  private void lexExponent() {
   626→    if (lookahead == '+' || lookahead == '-') {
   627→      nextChar();
   628→    }
   629→    if (lookahead == '_') {
   630→      throw lexError("invalidSeparatorPosition");
   631→    }
   632→    if (lookahead < 48 || lookahead > 57) {
   633→      throw unexpectedChar(lookahead, "number");
   634→    }
   635→    while ((lookahead >= 48 && lookahead <= 57) || lookahead == '_') {
   636→      nextChar();
   637→    }
   638→  }
   639→
   640→  private void lexDotNumber() {
   641→    if (lookahead == '_') {
   642→      throw lexError("invalidSeparatorPosition");
   643→    }
   644→    while ((lookahead >= 48 && lookahead <= 57) || lookahead == '_') {
   645→      nextChar();
   646→    }
   647→    if (lookahead == 'e' || lookahead == 'E') {
   648→      nextChar();
   649→      lexExponent();
   650→    }
   651→  }
   652→
   653→  private Token lexShebang() {
   654→    do {
   655→      nextChar();
   656→    } while (lookahead != '\n' && lookahead != '\r' && lookahead != EOF);
   657→    return Token.SHEBANG;
   658→  }
   659→
   660→  private boolean isHex(char ch) {
   661→    var code = (int) ch;
   662→    return (code >= 48 && code <= 57) || (code >= 97 && code <= 102) || (code >= 65 && code <= 70);
   663→  }
   664→
   665→  private static boolean isIdentifierStart(char c) {
   666→    return c == '_' || c == '$' || Character.isUnicodeIdentifierStart(c);
   667→  }
   668→
   669→  private static boolean isIdentifierPart(char c) {
   670→    return c != EOF && (c == '$' || Character.isUnicodeIdentifierPart(c));
   671→  }
   672→
   673→  private char nextChar() {
   674→    var tmp = lookahead;
   675→    cursor++;
   676→    if (cursor >= size) {
   677→      lookahead = EOF;
   678→    } else {
   679→      lookahead = source[cursor];
   680→    }
   681→    return tmp;
   682→  }
   683→
   684→  private void backup() {
   685→    lookahead = source[--cursor];
   686→  }
   687→
   688→  private void backup(int amount) {
   689→    cursor -= amount;
   690→    lookahead = source[cursor];
   691→  }
   692→
   693→  private ParserError lexError(String msg, Object... args) {
   694→    var length = lookahead == EOF ? 0 : 1;
   695→    var index = lookahead == EOF ? cursor - 1 : cursor;
   696→    return new ParserError(ErrorMessages.create(msg, args), new Span(index, length));
   697→  }
   698→
   699→  private ParserError lexError(String msg, int charIndex, int length) {
   700→    return new ParserError(msg, new Span(charIndex, length));
   701→  }
   702→
   703→  private ParserError lexError(String msg, Span span) {
   704→    return new ParserError(msg, span);
   705→  }
   706→
   707→  private ParserError unexpectedChar(char got, String didYouMean) {
   708→    return lexError("unexpectedCharacter", got, didYouMean);
   709→  }
   710→
   711→  private ParserError unexpectedChar(String got, String option1, String option2, String option3) {
   712→    return lexError("unexpectedCharacter3", got, option1, option2, option3);
   713→  }
   714→
   715→  private ParserError unexpectedEndOfFile() {
   716→    return lexError(ErrorMessages.create("unexpectedEndOfFile"), cursor, 0);
   717→  }
   718→
   719→  public static boolean isRegularIdentifier(String identifier) {
   720→    if (identifier.isEmpty()) return false;
   721→
   722→    if (isKeyword(identifier)) return false;
   723→
   724→    var firstCp = identifier.codePointAt(0);
   725→    return (firstCp == '$' || firstCp == '_' || Character.isUnicodeIdentifierStart(firstCp))
   726→        && identifier
   727→            .codePoints()
   728→            .skip(1)
   729→            .allMatch(cp -> cp == '$' || Character.isUnicodeIdentifierPart(cp));
   730→  }
   731→
   732→  public static String maybeQuoteIdentifier(String identifier) {
   733→    return isRegularIdentifier(identifier) ? identifier : "`" + identifier + "`";
   734→  }
   735→
   736→  private static boolean isKeyword(String text) {
   737→    return getKeywordOrIdentifier(text) != Token.IDENTIFIER;
   738→  }
   739→
   740→  private static Token getKeywordOrIdentifier(String keyword) {
   741→    return switch (keyword) {
   742→      case "_" -> Token.UNDERSCORE;
   743→      case "abstract" -> Token.ABSTRACT;
   744→      case "amends" -> Token.AMENDS;
   745→      case "as" -> Token.AS;
   746→      case "case" -> Token.CASE;
   747→      case "class" -> Token.CLASS;
   748→      case "const" -> Token.CONST;
   749→      case "delete" -> Token.DELETE;
   750→      case "else" -> Token.ELSE;
   751→      case "extends" -> Token.EXTENDS;
   752→      case "external" -> Token.EXTERNAL;
   753→      case "false" -> Token.FALSE;
   754→      case "fixed" -> Token.FIXED;
   755→      case "for" -> Token.FOR;
   756→      case "function" -> Token.FUNCTION;
   757→      case "hidden" -> Token.HIDDEN;
   758→      case "if" -> Token.IF;
   759→      case "import" -> Token.IMPORT;
   760→      case "in" -> Token.IN;
   761→      case "is" -> Token.IS;
   762→      case "let" -> Token.LET;
   763→      case "local" -> Token.LOCAL;
   764→      case "module" -> Token.MODULE;
   765→      case "new" -> Token.NEW;
   766→      case "nothing" -> Token.NOTHING;
   767→      case "null" -> Token.NULL;
   768→      case "open" -> Token.OPEN;
   769→      case "out" -> Token.OUT;
   770→      case "outer" -> Token.OUTER;
   771→      case "override" -> Token.OVERRIDE;
   772→      case "protected" -> Token.PROTECTED;
   773→      case "read" -> Token.READ;
   774→      case "record" -> Token.RECORD;
   775→      case "super" -> Token.SUPER;
   776→      case "switch" -> Token.SWITCH;
   777→      case "this" -> Token.THIS;
   778→      case "throw" -> Token.THROW;
   779→      case "trace" -> Token.TRACE;
   780→      case "true" -> Token.TRUE;
   781→      case "typealias" -> Token.TYPE_ALIAS;
   782→      case "unknown" -> Token.UNKNOWN;
   783→      case "vararg" -> Token.VARARG;
   784→      case "when" -> Token.WHEN;
   785→      default -> Token.IDENTIFIER;
   786→    };
   787→  }
   788→
   789→  private static class InterpolationScope {
   790→    final int quotes;
   791→    final int pounds;
   792→    int parens = 0;
   793→
   794→    protected InterpolationScope(int quotes, int pounds) {
   795→      this.quotes = quotes;
   796→      this.pounds = pounds;
   797→    }
   798→  }
   799→
   800→  private enum State {
   801→    DEFAULT,
   802→    STRING
   803→  }
   804→}
   805→

