    90→@SuppressWarnings("DuplicatedCode")
    91→public class Parser {
    92→
    93→  private Lexer lexer;
    94→  private Token lookahead;
    95→  private Span spanLookahead;
    96→  private boolean backtracking = false;
    97→  private FullToken prev;
    98→  private FullToken _lookahead;
    99→  private boolean precededBySemicolon = false;
   100→
   101→  public Parser() {}
   102→
   103→  private void init(String source) {
   104→    this.lexer = new Lexer(source);
   105→    _lookahead = forceNext();
   106→    lookahead = _lookahead.token;
   107→    spanLookahead = _lookahead.span;
   108→  }
   109→
   110→  public Module parseModule(String source) {
   111→    init(source);
   112→    if (lookahead == Token.EOF) {
   113→      return new Module(Collections.singletonList(null), new Span(0, 0));
   114→    }
   115→    var start = spanLookahead;
   116→    Span end = null;
   117→    ModuleDecl moduleDecl;
   118→    var nodes = new ArrayList<Node>();
   119→    try {
   120→      var header = parseMemberHeader();
   121→
   122→      moduleDecl = parseModuleDecl(header);
   123→      if (moduleDecl != null) {
   124→        end = moduleDecl.span();
   125→        header = null;
   126→      }
   127→      nodes.add(moduleDecl);
   128→      // imports
   129→      while (lookahead == Token.IMPORT || lookahead == Token.IMPORT_STAR) {
   130→        if (header != null && header.isNotEmpty()) {
   131→          throw parserError("wrongHeaders", "Imports");
   132→        }
   133→        var _import = parseImportDecl();
   134→        nodes.add(_import);
   135→        end = _import.span();
   136→      }
   137→
   138→      // entries
   139→      if (header != null && header.isNotEmpty()) {
   140→        end = parseModuleMember(header, nodes);
   141→      }
   142→
   143→      while (lookahead != Token.EOF) {
   144→        header = parseMemberHeader();
   145→        end = parseModuleMember(header, nodes);
   146→      }
   147→      return new Module(nodes, start.endWith(spanLookahead));
   148→    } catch (ParserError pe) {
   149→      var spanEnd = end != null ? end : start;
   150→      pe.setPartialParseResult(new Module(nodes, start.endWith(spanEnd)));
   151→      throw pe;
   152→    }
   153→  }
   154→
   155→  public Expr parseExpressionInput(String source) {
   156→    init(source);
   157→    var expr = parseExpr();
   158→    expect(Token.EOF, "unexpectedToken", "end of file");
   159→    return expr;
   160→  }
   161→
   162→  public ReplInput parseReplInput(String source) {
   163→    init(source);
   164→    var nodes = new ArrayList<Node>();
   165→    while (lookahead != Token.EOF) {
   166→      var header = parseMemberHeader();
   167→      switch (lookahead) {
   168→        case IMPORT, IMPORT_STAR -> {
   169→          ensureEmptyHeaders(header, "Imports");
   170→          nodes.add(parseImportDecl());
   171→        }
   172→        case MODULE, AMENDS, EXTENDS -> nodes.add(parseModuleDecl(header));
   173→        case CLASS -> nodes.add(parseClass(header));
   174→        case TYPE_ALIAS -> nodes.add(parseTypeAlias(header));
   175→        case FUNCTION -> nodes.add(parseClassMethod(header));
   176→        case IDENTIFIER -> {
   177→          next();
   178→          switch (lookahead) {
   179→            case COLON, ASSIGN, LBRACE -> {
   180→              backtrack();
   181→              nodes.add(parseClassProperty(header));
   182→            }
   183→            default -> {
   184→              backtrack();
   185→              ensureEmptyHeaders(header, "Expressions");
   186→              nodes.add(parseExpr());
   187→            }
   188→          }
   189→        }
   190→        default -> {
   191→          ensureEmptyHeaders(header, "Expressions");
   192→          nodes.add(parseExpr());
   193→        }
   194→      }
   195→    }
   196→    Span span;
   197→    if (nodes.isEmpty()) {
   198→      span = new Span(0, 0);
   199→    } else {
   200→      span = nodes.get(0).span().endWith(nodes.get(nodes.size() - 1).span());
   201→    }
   202→    return new ReplInput(nodes, span);
   203→  }
   204→
   205→  private @Nullable ModuleDecl parseModuleDecl(MemberHeader header) {
   206→    QualifiedIdentifier moduleName = null;
   207→    Keyword moduleKeyword = null;
   208→    var start = header.span();
   209→    Span end = null;
   210→    if (lookahead == Token.MODULE) {
   211→      var module = expect(Token.MODULE, "unexpectedToken", "module");
   212→      moduleKeyword = new Keyword(module.span);
   213→      if (start == null) {
   214→        start = module.span;
   215→      }
   216→      moduleName = parseQualifiedIdentifier();
   217→      end = moduleName.span();
   218→    }
   219→    var extendsOrAmendsDecl = parseExtendsAmendsDecl();
   220→    if (extendsOrAmendsDecl != null) {
   221→      if (start == null) {
   222→        start = extendsOrAmendsDecl.span();
   223→      }
   224→      end = extendsOrAmendsDecl.span();
   225→    }
   226→    if (moduleName != null || extendsOrAmendsDecl != null) {
   227→      var children = new ArrayList<Node>();
   228→      children.add(header.docComment);
   229→      children.addAll(header.annotations);
   230→      var modifiersOffset = children.size();
   231→      children.addAll(header.modifiers);
   232→      var nameOffset = children.size();
   233→      children.add(moduleKeyword);
   234→      children.add(moduleName);
   235→      children.add(extendsOrAmendsDecl);
   236→      return new ModuleDecl(children, modifiersOffset, nameOffset, start.endWith(end));
   237→    }
   238→    return null;
   239→  }
   240→
   241→  private QualifiedIdentifier parseQualifiedIdentifier() {
   242→    var idents = parseListOf(Token.DOT, this::parseIdentifier);
   243→    return new QualifiedIdentifier(idents);
   244→  }
   245→
   246→  private @Nullable ExtendsOrAmendsClause parseExtendsAmendsDecl() {
   247→    if (lookahead == Token.EXTENDS) {
   248→      var tk = next().span;
   249→      var url = parseStringConstant();
   250→      return new ExtendsOrAmendsClause(
   251→          url, ExtendsOrAmendsClause.Type.EXTENDS, tk.endWith(url.span()));
   252→    }
   253→    if (lookahead == Token.AMENDS) {
   254→      var tk = next().span;
   255→      var url = parseStringConstant();
   256→      return new ExtendsOrAmendsClause(
   257→          url, ExtendsOrAmendsClause.Type.AMENDS, tk.endWith(url.span()));
   258→    }
   259→    return null;
   260→  }
   261→
   262→  private ImportClause parseImportDecl() {
   263→    Span start;
   264→    boolean isGlob = false;
   265→    if (lookahead == Token.IMPORT_STAR) {
   266→      start = next().span;
   267→      isGlob = true;
   268→    } else {
   269→      start = expect(Token.IMPORT, "unexpectedToken2", "import", "import*").span;
   270→    }
   271→    var str = parseStringConstant();
   272→    var end = str.span();
   273→    Identifier alias = null;
   274→    if (lookahead == Token.AS) {
   275→      next();
   276→      alias = parseIdentifier();
   277→      end = alias.span();
   278→    }
   279→    return new ImportClause(str, isGlob, alias, start.endWith(end));
   280→  }
   281→
   282→  private MemberHeader parseMemberHeader() {
   283→    DocComment docComment = null;
   284→    var annotations = new ArrayList<Annotation>();
   285→    var modifiers = new ArrayList<Modifier>();
   286→    if (lookahead == Token.DOC_COMMENT) {
   287→      docComment = parseDocComment();
   288→    }
   289→    while (lookahead == Token.AT) {
   290→      annotations.add(parseAnnotation());
   291→    }
   292→    while (lookahead.isModifier()) {
   293→      modifiers.add(parseModifier());
   294→    }
   295→    return new MemberHeader(docComment, annotations, modifiers);
   296→  }
   297→
   298→  private DocComment parseDocComment() {
   299→    var spans = new ArrayList<Span>();
   300→    spans.add(nextComment().span);
   301→    while (lookahead == Token.DOC_COMMENT
   302→        || lookahead == Token.LINE_COMMENT
   303→        || lookahead == Token.BLOCK_COMMENT) {
   304→      var next = nextComment();
   305→      // newlines are not allowed in doc comments
   306→      if (next.newLinesBetween > 1) {
   307→        if (next.token == Token.DOC_COMMENT) {
   308→          backtrack();
   309→        }
   310→        break;
   311→      }
   312→      if (next.token == Token.DOC_COMMENT) {
   313→        spans.add(next.span);
   314→      }
   315→    }
   316→    while (lookahead == Token.LINE_COMMENT || lookahead == Token.BLOCK_COMMENT) {
   317→      nextComment();
   318→    }
   319→    return new DocComment(spans);
   320→  }
   321→
   322→  private Span parseModuleMember(MemberHeader header, List<Node> nodes) {
   323→    switch (lookahead) {
   324→      case IDENTIFIER -> {
   325→        var node = parseClassProperty(header);
   326→        nodes.add(node);
   327→        return node.span();
   328→      }
   329→      case TYPE_ALIAS -> {
   330→        var node = parseTypeAlias(header);
   331→        nodes.add(node);
   332→        return node.span();
   333→      }
   334→      case CLASS -> {
   335→        var node = parseClass(header);
   336→        nodes.add(node);
   337→        return node.span();
   338→      }
   339→      case FUNCTION -> {
   340→        var node = parseClassMethod(header);
   341→        nodes.add(node);
   342→        return node.span();
   343→      }
   344→      case EOF -> throw parserError("unexpectedEndOfFile");
   345→      default -> {
   346→        if (lookahead.isKeyword()) {
   347→          throw parserError("keywordNotAllowedHere", lookahead.text());
   348→        }
   349→        if (lookahead == Token.DOC_COMMENT) {
   350→          throw parserError("danglingDocComment");
   351→        }
   352→        throw parserError("invalidTopLevelToken");
   353→      }
   354→    }
   355→  }
   356→
   357→  private TypeAlias parseTypeAlias(MemberHeader header) {
   358→    var typeAlias = next().span;
   359→    var startSpan = header.span(typeAlias);
   360→
   361→    var identifier = parseIdentifier();
   362→    TypeParameterList typePars = null;
   363→    if (lookahead == Token.LT) {
   364→      typePars = parseTypeParameterList();
   365→    }
   366→    expect(Token.ASSIGN, "unexpectedToken", "=");
   367→    var type = parseType();
   368→    var children = new ArrayList<Node>(header.annotations.size() + header.modifiers.size() + 5);
   369→    children.add(header.docComment);
   370→    children.addAll(header.annotations);
   371→    var modifiersOffset = header.annotations.size() + 1;
   372→    children.addAll(header.modifiers);
   373→    var nameOffset = modifiersOffset + header.modifiers.size();
   374→    children.add(new Keyword(typeAlias));
   375→    children.add(identifier);
   376→    children.add(typePars);
   377→    children.add(type);
   378→    return new TypeAlias(children, modifiersOffset, nameOffset, startSpan.endWith(type.span()));
   379→  }
   380→
   381→  private Class parseClass(MemberHeader header) {
   382→    var classKeyword = next();
   383→    var startSpan = header.span(classKeyword.span);
   384→    var children = new ArrayList<Node>();
   385→    children.add(header.docComment);
   386→    children.addAll(header.annotations);
   387→    var modifiersOffset = header.annotations.size() + 1;
   388→    children.addAll(header.modifiers);
   389→    var nameOffset = modifiersOffset + header.modifiers.size();
   390→    children.add(new Keyword(classKeyword.span));
   391→    var name = parseIdentifier();
   392→    children.add(name);
   393→    TypeParameterList typePars = null;
   394→    var end = name.span();
   395→    if (lookahead == Token.LT) {
   396→      typePars = parseTypeParameterList();
   397→      end = typePars.span();
   398→    }
   399→    children.add(typePars);
   400→    Type superClass = null;
   401→    if (lookahead == Token.EXTENDS) {
   402→      next();
   403→      superClass = parseType();
   404→      end = superClass.span();
   405→    }
   406→    children.add(superClass);
   407→
   408→    ClassBody body = null;
   409→    if (lookahead == Token.LBRACE) {
   410→      body = parseClassBody();
   411→      end = body.span();
   412→    }
   413→    children.add(body);
   414→
   415→    return new Class(children, modifiersOffset, nameOffset, startSpan.endWith(end));
   416→  }
   417→
   418→  private ClassBody parseClassBody() {
   419→    var start = expect(Token.LBRACE, "missingDelimiter", "{").span;
   420→    var children = new ArrayList<Node>();
   421→    while (lookahead != Token.RBRACE && lookahead != Token.EOF) {
   422→      var entryHeader = parseMemberHeader();
   423→      if (lookahead == Token.FUNCTION) {
   424→        children.add(parseClassMethod(entryHeader));
   425→      } else {
   426→        children.add(parseClassProperty(entryHeader));
   427→      }
   428→    }
   429→    if (lookahead == Token.EOF) {
   430→      throw new ParserError(
   431→          ErrorMessages.create("missingDelimiter", "}"), prev.span.stopSpan().move(1));
   432→    }
   433→    var end = expect(Token.RBRACE, "missingDelimiter", "}").span;
   434→    return new ClassBody(children, start.endWith(end));
   435→  }
   436→
   437→  private ClassProperty parseClassProperty(MemberHeader header) {
   438→    var name = parseIdentifier();
   439→    var start = header.span(name.span());
   440→    var children = new ArrayList<Node>();
   441→    children.add(header.docComment);
   442→    children.addAll(header.annotations);
   443→    var modifiersOffset = header.annotations.size() + 1;
   444→    children.addAll(header.modifiers);
   445→    var nameOffset = modifiersOffset + header.modifiers.size();
   446→    TypeAnnotation typeAnnotation = null;
   447→    Expr expr = null;
   448→    var bodies = new ArrayList<ObjectBody>();
   449→    if (lookahead == Token.COLON) {
   450→      typeAnnotation = parseTypeAnnotation();
   451→    }
   452→    if (lookahead == Token.ASSIGN) {
   453→      next();
   454→      expr = parseExpr();
   455→    } else if (lookahead == Token.LBRACE) {
   456→      if (typeAnnotation != null) {
   457→        throw parserError("typeAnnotationInAmends");
   458→      }
   459→      while (lookahead == Token.LBRACE) {
   460→        bodies.add(parseObjectBody());
   461→      }
   462→    }
   463→    children.add(name);
   464→    children.add(typeAnnotation);
   465→    children.add(expr);
   466→    children.addAll(bodies);
   467→    if (expr != null) {
   468→      return new ClassProperty(children, modifiersOffset, nameOffset, start.endWith(expr.span()));
   469→    }
   470→    if (!bodies.isEmpty()) {
   471→      return new ClassProperty(
   472→          children,
   473→          modifiersOffset,
   474→          nameOffset,
   475→          start.endWith(bodies.get(bodies.size() - 1).span()));
   476→    }
   477→    if (typeAnnotation == null) {
   478→      throw new ParserError(ErrorMessages.create("invalidProperty"), name.span());
   479→    }
   480→    return new ClassProperty(
   481→        children, modifiersOffset, nameOffset, start.endWith(typeAnnotation.span()));
   482→  }
   483→
   484→  private ClassMethod parseClassMethod(MemberHeader header) {
   485→    var func = expect(Token.FUNCTION, "unexpectedToken", "function").span;
   486→    var start = header.span(func);
   487→    var headerSpanStart = header.modifierSpan(func);
   488→    var children = new ArrayList<Node>();
   489→    children.add(header.docComment);
   490→    children.addAll(header.annotations);
   491→    var modifiersOffset = header.annotations.size() + 1;
   492→    children.addAll(header.modifiers);
   493→    var nameOffset = modifiersOffset + header.modifiers.size();
   494→    var name = parseIdentifier();
   495→    children.add(name);
   496→    TypeParameterList typePars = null;
   497→    if (lookahead == Token.LT) {
   498→      typePars = parseTypeParameterList();
   499→    }
   500→    children.add(typePars);
   501→    var parameterList = parseParameterList();
   502→    children.add(parameterList);
   503→    var end = parameterList.span();
   504→    var endHeader = end;
   505→    TypeAnnotation typeAnnotation = null;
   506→    if (lookahead == Token.COLON) {
   507→      typeAnnotation = parseTypeAnnotation();
   508→      end = typeAnnotation.span();
   509→      endHeader = end;
