   513→    if (lookahead == Token.ASSIGN) {
   514→      next();
   515→      expr = parseExpr();
   516→      end = expr.span();
   517→    }
   518→    children.add(expr);
   519→    return new ClassMethod(
   520→        children,
   521→        modifiersOffset,
   522→        nameOffset,
   523→        headerSpanStart.endWith(endHeader),
   524→        start.endWith(end));
