   527→  private ObjectBody parseObjectBody() {
   528→    var start = expect(Token.LBRACE, "unexpectedToken", "{").span;
   529→    List<Node> nodes = new ArrayList<>();
   530→    var membersOffset = -1;
   531→    if (lookahead == Token.RBRACE) {
   532→      return new ObjectBody(List.of(), 0, start.endWith(next().span));
   533→    } else if (lookahead == Token.UNDERSCORE) {
   534→      // it's a parameter
   535→      nodes.addAll(parseListOfParameter(Token.COMMA));
   536→      expect(Token.ARROW, "unexpectedToken2", ",", "->");
   537→    } else if (lookahead == Token.IDENTIFIER) {
   538→      // not sure what it is yet
   539→      var identifier = parseIdentifier();
   540→      if (lookahead == Token.ARROW) {
   541→        // it's a parameter
   542→        next();
   543→        nodes.add(new TypedIdentifier(identifier, null, identifier.span()));
   544→      } else if (lookahead == Token.COMMA) {
   545→        // it's a parameter
   546→        backtrack();
   547→        nodes.addAll(parseListOfParameter(Token.COMMA));
   548→        expect(Token.ARROW, "unexpectedToken2", ",", "->");
   549→      } else if (lookahead == Token.COLON) {
   550→        // still not sure
   551→        var colon = next().span;
   552→        var type = parseType();
   553→        var typeAnnotation = new TypeAnnotation(type, colon.endWith(type.span()));
   554→        if (lookahead == Token.COMMA) {
   555→          // it's a parameter
   556→          next();
   557→          nodes.add(
   558→              new TypedIdentifier(
   559→                  identifier, typeAnnotation, identifier.span().endWith(type.span())));
   560→          nodes.addAll(parseListOfParameter(Token.COMMA));
   561→          expect(Token.ARROW, "unexpectedToken2", ",", "->");
   562→        } else if (lookahead == Token.ARROW) {
   563→          // it's a parameter
   564→          next();
   565→          nodes.add(
   566→              new TypedIdentifier(
   567→                  identifier, typeAnnotation, identifier.span().endWith(type.span())));
   568→        } else {
   569→          // it's a member
   570→          expect(Token.ASSIGN, "unexpectedToken", "=");
   571→          var expr = parseExpr();
   572→          membersOffset = 0;
   573→          nodes.add(
   574→              new ObjectMember.ObjectProperty(
   575→                  Arrays.asList(identifier, typeAnnotation, expr),
   576→                  0,
   577→                  identifier.span().endWith(expr.span())));
   578→        }
   579→      } else {
   580→        // member
   581→        backtrack();
   582→      }
   583→    }
   584→
   585→    if (membersOffset < 0) {
   586→      membersOffset = nodes.size();
   587→    }
   588→    // members
   589→    while (lookahead != Token.RBRACE) {
   590→      if (lookahead == Token.EOF) {
   591→        throw new ParserError(
   592→            ErrorMessages.create("missingDelimiter", "}"), prev.span.stopSpan().move(1));
   593→      }
   594→      nodes.add(parseObjectMember());
   595→    }
   596→    var end = next().span;
   597→    return new ObjectBody(nodes, membersOffset, start.endWith(end));
   598→  }
