   600→  private ObjectMember parseObjectMember() {
   601→    return switch (lookahead) {
   602→      case IDENTIFIER -> {
   603→        next();
   604→        if (lookahead == Token.LBRACE || lookahead == Token.COLON || lookahead == Token.ASSIGN) {
   605→          // it's an objectProperty
   606→          backtrack();
   607→          yield parseObjectProperty(null);
   608→        } else {
   609→          backtrack();
   610→          // it's an expression
   611→          yield parseObjectElement();
   612→        }
   613→      }
   614→      case FUNCTION -> parseObjectMethod(List.of());
   615→      case LPRED -> parseMemberPredicate();
   616→      case LBRACK -> parseObjectEntry();
   617→      case SPREAD, QSPREAD -> parseObjectSpread();
   618→      case WHEN -> parseWhenGenerator();
   619→      case FOR -> parseForGenerator();
   620→      case TYPE_ALIAS, CLASS ->
   621→          throw new ParserError(
   622→              ErrorMessages.create("missingDelimiter", "}"), prev.span.stopSpan().move(1));
   623→      default -> {
   624→        var modifiers = new ArrayList<Modifier>();
   625→        while (lookahead.isModifier()) {
   626→          modifiers.add(parseModifier());
   627→        }
   628→        if (!modifiers.isEmpty()) {
   629→          if (lookahead == Token.FUNCTION) {
   630→            yield parseObjectMethod(modifiers);
   631→          } else {
   632→            yield parseObjectProperty(modifiers);
   633→          }
   634→        } else {
   635→          yield parseObjectElement();
   636→        }
   637→      }
   638→    };
   639→  }
