   646→  private ObjectMember parseObjectProperty(@Nullable List<Modifier> modifiers) {
   647→    var start = spanLookahead;
   648→    if (modifiers != null && !modifiers.isEmpty()) {
   649→      start = modifiers.get(0).span();
   650→    }
   651→    var allModifiers = modifiers;
   652→    if (allModifiers == null) {
   653→      allModifiers = parseModifierList();
   654→    }
   655→    var identifier = parseIdentifier();
   656→    TypeAnnotation typeAnnotation = null;
   657→    if (lookahead == Token.COLON) {
   658→      typeAnnotation = parseTypeAnnotation();
   659→    }
   660→    if (typeAnnotation != null || lookahead == Token.ASSIGN) {
   661→      expect(Token.ASSIGN, "unexpectedToken", "=");
   662→      var expr = parseExpr("}");
   663→      var nodes = new ArrayList<Node>(allModifiers.size() + 4);
   664→      nodes.addAll(allModifiers);
   665→      nodes.add(identifier);
   666→      nodes.add(typeAnnotation);
   667→      nodes.add(expr);
   668→      return new ObjectMember.ObjectProperty(
   669→          nodes, allModifiers.size(), start.endWith(expr.span()));
   670→    }
   671→    var bodies = parseBodyList();
   672→    var end = bodies.get(bodies.size() - 1).span();
   673→    var nodes = new ArrayList<Node>(allModifiers.size() + 4);
   674→    nodes.addAll(allModifiers);
   675→    nodes.add(identifier);
   676→    nodes.add(null);
   677→    nodes.add(null);
   678→    nodes.addAll(bodies);
   679→    return new ObjectMember.ObjectProperty(nodes, allModifiers.size(), start.endWith(end));
   680→  }
