   682→  private ObjectMember.ObjectMethod parseObjectMethod(List<Modifier> modifiers) {
   683→    var start = spanLookahead;
   684→    if (!modifiers.isEmpty()) {
   685→      start = modifiers.get(0).span();
   686→    }
   687→    var function = expect(Token.FUNCTION, "unexpectedToken", "function").span;
   688→    var identifier = parseIdentifier();
   689→    TypeParameterList params = null;
   690→    if (lookahead == Token.LT) {
   691→      params = parseTypeParameterList();
   692→    }
   693→    var args = parseParameterList();
   694→    TypeAnnotation typeAnnotation = null;
   695→    if (lookahead == Token.COLON) {
   696→      typeAnnotation = parseTypeAnnotation();
   697→    }
   698→    expect(Token.ASSIGN, "unexpectedToken", "=");
   699→    var expr = parseExpr("}");
