   704→    nodes.add(params);
   705→    nodes.add(args);
   706→    nodes.add(typeAnnotation);
   707→    nodes.add(expr);
   708→    return new ObjectMember.ObjectMethod(nodes, modifiers.size(), start.endWith(expr.span()));
