   711→  private ObjectMember parseMemberPredicate() {
   712→    var start = next().span;
   713→    var pred = parseExpr("]]");
   714→    var firstBrack = expect(Token.RBRACK, "unexpectedToken", "]]").span;
   715→    Span secondbrack;
   716→    if (lookahead != Token.RBRACK) {
   717→      var text = _lookahead.text(lexer);
   718→      throw new ParserError(ErrorMessages.create("unexpectedToken", text, "]]"), firstBrack);
   719→    } else {
   720→      secondbrack = next().span;
   721→    }
   722→    if (firstBrack.charIndex() != secondbrack.charIndex() - 1) {
   723→      // There shouldn't be any whitespace between the first and second ']'.
   724→      var span = firstBrack.endWith(secondbrack);
   725→      var text = lexer.textFor(span.charIndex(), span.length());
   726→      throw new ParserError(ErrorMessages.create("unexpectedToken", text, "]]"), firstBrack);
   727→    }
   728→    if (lookahead == Token.ASSIGN) {
   729→      next();
   730→      var expr = parseExpr("}");
   731→      return new ObjectMember.MemberPredicate(List.of(pred, expr), start.endWith(expr.span()));
   732→    }
   733→    var bodies = parseBodyList();
   734→    var end = bodies.get(bodies.size() - 1).span();
   735→    var nodes = new ArrayList<Node>(bodies.size() + 2);
   736→    nodes.add(pred);
   737→    nodes.add(null);
   738→    nodes.addAll(bodies);
   739→    return new ObjectMember.MemberPredicate(nodes, start.endWith(end));
   740→  }
