   808→  private Expr parseExpr(@Nullable String expectation, int minPrecedence) {
   809→    var expr = parseExprAtom(expectation);
   810→    var op = getOperator();
   811→    while (op != null) {
   812→      if (op.getPrec() < minPrecedence) break;
   813→      // `-` must be in the same line as the left operand and have no semicolons inbetween
   814→      if (op == Operator.MINUS && (precededBySemicolon || _lookahead.newLinesBetween > 0)) break;
   815→
   816→      next(); // operator
   817→      switch (op) {
   818→        case IS -> {
   819→          var type = parseType();
   820→          expr = new Expr.TypeCheckExpr(expr, type, expr.span().endWith(type.span()));
   821→        }
   822→        case AS -> {
   823→          var type = parseType();
   824→          expr = new Expr.TypeCastExpr(expr, type, expr.span().endWith(type.span()));
   825→        }
   826→        case DOT, QDOT -> {
   827→          var rhs = parseIdentifier();
   828→          var isNullable = op == Operator.QDOT;
   829→          ArgumentList argumentList = null;
   830→          if (lookahead == Token.LPAREN
   831→              && !precededBySemicolon
   832→              && _lookahead.newLinesBetween == 0) {
   833→            argumentList = parseArgumentList();
   834→          }
   835→          var lastSpan = argumentList != null ? argumentList.span() : rhs.span();
   836→          expr =
   837→              new QualifiedAccessExpr(
   838→                  expr, rhs, isNullable, argumentList, expr.span().endWith(lastSpan));
   839→        }
   840→        default -> {
   841→          var nextMinPrec = op.isLeftAssoc() ? op.getPrec() + 1 : op.getPrec();
   842→          var rhs = parseExpr(expectation, nextMinPrec);
   843→          expr = new BinaryOperatorExpr(expr, rhs, op, expr.span().endWith(rhs.span()));
   844→        }
   845→      }
   846→      op = getOperator();
   847→    }
   848→    return expr;
   849→  }
   850→
   851→  private @Nullable Operator getOperator() {
   852→    return switch (lookahead) {
   853→      case POW -> Operator.POW;
   854→      case STAR -> Operator.MULT;
   855→      case DIV -> Operator.DIV;
   856→      case INT_DIV -> Operator.INT_DIV;
   857→      case MOD -> Operator.MOD;
   858→      case PLUS -> Operator.PLUS;
   859→      case MINUS -> Operator.MINUS;
   860→      case GT -> Operator.GT;
   861→      case GTE -> Operator.GTE;
   862→      case LT -> Operator.LT;
   863→      case LTE -> Operator.LTE;
   864→      case IS -> Operator.IS;
   865→      case AS -> Operator.AS;
   866→      case EQUAL -> Operator.EQ_EQ;
   867→      case NOT_EQUAL -> Operator.NOT_EQ;
   868→      case AND -> Operator.AND;
   869→      case OR -> Operator.OR;
   870→      case PIPE -> Operator.PIPE;
   871→      case COALESCE -> Operator.NULL_COALESCE;
   872→      case DOT -> Operator.DOT;
   873→      case QDOT -> Operator.QDOT;
   874→      default -> null;
   875→    };
   876→  }
