   878→  private Expr parseExprAtom(@Nullable String expectation) {
   879→    var expr =
   880→        switch (lookahead) {
   881→          case THIS -> new ThisExpr(next().span);
   882→          case OUTER -> new OuterExpr(next().span);
   883→          case MODULE -> new ModuleExpr(next().span);
   884→          case NULL -> new NullLiteralExpr(next().span);
   885→          case THROW -> {
   886→            var start = next().span;
   887→            expect(Token.LPAREN, "unexpectedToken", "(");
   888→            var exp = parseExpr(")");
   889→            var end = expect(Token.RPAREN, "unexpectedToken", ")").span;
   890→            yield new ThrowExpr(exp, start.endWith(end));
   891→          }
   892→          case TRACE -> {
   893→            var start = next().span;
   894→            expect(Token.LPAREN, "unexpectedToken", "(");
   895→            var exp = parseExpr(")");
   896→            var end = expect(Token.RPAREN, "unexpectedToken", ")").span;
   897→            yield new TraceExpr(exp, start.endWith(end));
   898→          }
   899→          case IMPORT -> {
   900→            var start = next().span;
   901→            expect(Token.LPAREN, "unexpectedToken", "(");
   902→            var strConst = parseStringConstant();
   903→            var end = expect(Token.RPAREN, "unexpectedToken", ")").span;
   904→            yield new Expr.ImportExpr(strConst, false, start.endWith(end));
   905→          }
   906→          case IMPORT_STAR -> {
   907→            var start = next().span;
   908→            expect(Token.LPAREN, "unexpectedToken", "(");
   909→            var strConst = parseStringConstant();
   910→            var end = expect(Token.RPAREN, "unexpectedToken", ")").span;
   911→            yield new Expr.ImportExpr(strConst, true, start.endWith(end));
   912→          }
   913→          case READ, READ_STAR, READ_QUESTION -> {
   914→            var readType =
   915→                switch (lookahead) {
   916→                  case READ_QUESTION -> ReadType.NULL;
   917→                  case READ_STAR -> ReadType.GLOB;
   918→                  default -> ReadType.READ;
   919→                };
   920→            var start = next().span;
   921→            expect(Token.LPAREN, "unexpectedToken", "(");
   922→            var exp = parseExpr(")");
   923→            var end = expect(Token.RPAREN, "unexpectedToken", ")").span;
   924→            yield new ReadExpr(exp, readType, start.endWith(end));
   925→          }
   926→          case NEW -> {
   927→            var start = next().span;
   928→            Type type = null;
   929→            if (lookahead != Token.LBRACE) {
   930→              type = parseType("{");
   931→            }
   932→            var body = parseObjectBody();
   933→            yield new NewExpr(type, body, start.endWith(body.span()));
   934→          }
   935→          case MINUS -> {
   936→            var start = next().span;
   937→            // calling `parseExprAtom` here and not `parseExpr` because
   938→            // unary minus has higher precendence than binary operators
   939→            var exp = parseExprAtom(expectation);
   940→            yield new UnaryMinusExpr(exp, start.endWith(exp.span()));
   941→          }
   942→          case NOT -> {
   943→            var start = next().span;
   944→            // calling `parseExprAtom` here and not `parseExpr` because
   945→            // logical not has higher precendence than binary operators
   946→            var exp = parseExprAtom(expectation);
   947→            yield new LogicalNotExpr(exp, start.endWith(exp.span()));
   948→          }
   949→          case LPAREN -> {
   950→            // can be function literal or parenthesized expression
   951→            var start = next().span;
   952→            yield switch (lookahead) {
   953→              case UNDERSCORE -> parseFunctionLiteral(start);
   954→              case IDENTIFIER -> parseFunctionLiteralOrParenthesized(start);
   955→              case RPAREN -> {
   956→                var endParen = next().span;
   957→                var paramList = new ParameterList(List.of(), start.endWith(endParen));
   958→                expect(Token.ARROW, "unexpectedToken", "->");
   959→                var exp = parseExpr(expectation);
   960→                yield new FunctionLiteralExpr(paramList, exp, start.endWith(exp.span()));
   961→              }
   962→              default -> {
   963→                // expression
   964→                var exp = parseExpr(")");
   965→                var end = expect(Token.RPAREN, "unexpectedToken", ")").span;
