   975→              if (lookahead == Token.LPAREN) {
   976→                var args = parseArgumentList();
   977→                yield new SuperAccessExpr(identifier, args, start.endWith(args.span()));
   978→              } else {
   979→                yield new SuperAccessExpr(identifier, null, start.endWith(identifier.span()));
   980→              }
   981→            } else {
   982→              expect(Token.LBRACK, "unexpectedToken", "[");
   983→              var exp = parseExpr("]");
   984→              var end = expect(Token.RBRACK, "unexpectedToken", "]").span;
