   989→            var start = next().span;
   990→            expect(Token.LPAREN, "unexpectedToken", "(");
   991→            var pred = parseExpr(")");
   992→            expect(Token.RPAREN, "unexpectedToken", ")");
   993→            var then = parseExpr("else");
   994→            expect(Token.ELSE, "unexpectedToken", "else");
   995→            var elseCase = parseExpr(expectation);
   996→            yield new IfExpr(pred, then, elseCase, start.endWith(elseCase.span()));
