   999→            var start = next().span();
  1000→            expect(Token.LPAREN, "unexpectedToken", "(");
  1001→            var param = parseParameter();
  1002→            expect(Token.ASSIGN, "unexpectedToken", "=");
  1003→            var bindExpr = parseExpr(")");
  1004→            expect(Token.RPAREN, "unexpectedToken", ")");
  1005→            var exp = parseExpr(expectation);
