  1008→          case TRUE -> new BoolLiteralExpr(true, next().span);
  1009→          case FALSE -> new BoolLiteralExpr(false, next().span);
  1010→          case INT, HEX, BIN, OCT -> {
  1011→            var tk = next();
  1012→            yield new IntLiteralExpr(tk.text(lexer), tk.span);
  1013→          }
  1014→          case FLOAT -> {
  1015→            var tk = next();
  1016→            yield new FloatLiteralExpr(tk.text(lexer), tk.span);
  1017→          }
  1018→          case STRING_START -> parseSingleLineStringLiteralExpr();
  1019→          case STRING_MULTI_START -> parseMultiLineStringLiteralExpr();
