  1021→            var identifier = parseIdentifier();
  1022→            if (lookahead == Token.LPAREN
  1023→                && !precededBySemicolon
  1024→                && _lookahead.newLinesBetween == 0) {
  1025→              var args = parseArgumentList();
  1026→              yield new UnqualifiedAccessExpr(
  1027→                  identifier, args, identifier.span().endWith(args.span()));
  1028→            } else {
  1029→              yield new UnqualifiedAccessExpr(identifier, null, identifier.span());
  1030→            }
