  1036→            var text = _lookahead.text(lexer);
  1037→            if (expectation != null) {
  1038→              throw parserError("unexpectedToken", text, expectation);
  1039→            }
  1040→            throw parserError("unexpectedTokenForExpression", text);
  1041→          }
  1042→        };
  1043→    return parseExprRest(expr);
  1044→  }
  1045→
  1046→  @SuppressWarnings("DuplicatedCode")
  1047→  private Expr parseExprRest(Expr expr) {
  1048→    // non null
  1049→    if (lookahead == Token.NON_NULL) {
  1050→      var end = next().span;
  1051→      var res = new NonNullExpr(expr, expr.span().endWith(end));
  1052→      return parseExprRest(res);
  1053→    }
  1054→    // amends
  1055→    if (lookahead == Token.LBRACE) {
  1056→      if (expr instanceof ParenthesizedExpr
  1057→          || expr instanceof AmendsExpr
  1058→          || expr instanceof NewExpr) {
  1059→        var body = parseObjectBody();
