  1089→  private Expr parseSingleLineStringLiteralExpr() {
  1090→    var start = next();
  1091→    var parts = new ArrayList<StringPart>();
  1092→    var builder = new StringBuilder();
  1093→    var startSpan = spanLookahead;
  1094→    var end = spanLookahead;
  1095→    while (lookahead != Token.STRING_END) {
  1096→      switch (lookahead) {
  1097→        case STRING_PART -> {
  1098→          var tk = next();
  1099→          end = tk.span;
  1100→          builder.append(tk.text(lexer));
  1101→        }
  1102→        case STRING_ESCAPE_NEWLINE -> {
  1103→          end = next().span;
  1104→          builder.append('\n');
  1105→        }
  1106→        case STRING_ESCAPE_TAB -> {
  1107→          end = next().span;
  1108→          builder.append('\t');
  1109→        }
  1110→        case STRING_ESCAPE_QUOTE -> {
  1111→          end = next().span;
  1112→          builder.append('"');
  1113→        }
  1114→        case STRING_ESCAPE_BACKSLASH -> {
  1115→          end = next().span;
  1116→          builder.append('\\');
  1117→        }
  1118→        case STRING_ESCAPE_RETURN -> {
  1119→          end = next().span;
  1120→          builder.append('\r');
  1121→        }
  1122→        case STRING_ESCAPE_UNICODE -> {
  1123→          var tk = next();
  1124→          end = tk.span;
  1125→          builder.append(parseUnicodeEscape(tk));
  1126→        }
  1127→        case INTERPOLATION_START -> {
  1128→          var istart = next().span;
  1129→          if (!builder.isEmpty()) {
  1130→            assert startSpan != null;
  1131→            parts.add(new StringChars(builder.toString(), startSpan.endWith(end)));
  1132→            builder = new StringBuilder();
  1133→          }
  1134→          var exp = parseExpr(")");
  1135→          end = expect(Token.RPAREN, "unexpectedToken", ")").span;
  1136→          parts.add(new StringPart.StringInterpolation(exp, istart.endWith(end)));
  1137→          startSpan = spanLookahead;
  1138→        }
  1139→        case EOF -> {
  1140→          var delimiter = new StringBuilder(start.text(lexer)).reverse().toString();
  1141→          throw parserError("missingDelimiter", delimiter);
  1142→        }
  1143→      }
  1144→    }
  1145→    if (!builder.isEmpty()) {
  1146→      parts.add(new StringChars(builder.toString(), startSpan.endWith(end)));
  1147→    }
  1148→    end = next().span;
  1149→    return new SingleLineStringLiteralExpr(parts, start.span, end, start.span.endWith(end));
  1150→  }
