  1152→  private Expr parseMultiLineStringLiteralExpr() {
  1153→    var start = next();
  1154→    var stringTokens = new ArrayList<TempNode>();
  1155→    while (lookahead != Token.STRING_END) {
  1156→      switch (lookahead) {
  1157→        case STRING_PART,
  1158→            STRING_NEWLINE,
  1159→            STRING_ESCAPE_NEWLINE,
  1160→            STRING_ESCAPE_TAB,
  1161→            STRING_ESCAPE_QUOTE,
  1162→            STRING_ESCAPE_BACKSLASH,
  1163→            STRING_ESCAPE_RETURN,
  1164→            STRING_ESCAPE_UNICODE ->
  1165→            stringTokens.add(new TempNode(next(), null));
  1166→        case INTERPOLATION_START -> {
  1167→          var istart = next();
  1168→          var exp = parseExpr(")");
  1169          var end = expect(Token.RPAREN, "unexpectedToken", ")").span;
  1170→          var interpolation = new StringPart.StringInterpolation(exp, istart.span.endWith(end));
  1171→          stringTokens.add(new TempNode(null, interpolation));
  1172→        }
  1173→        case EOF -> {
  1174→          var delimiter = new StringBuilder(start.text(lexer)).reverse().toString();
  1175→          throw parserError("missingDelimiter", delimiter);
  1176→        }
  1177→      }
  1178→    }
  1179→    var end = next().span;
  1180→    var fullSpan = start.span.endWith(end);
  1181→    var parts = validateMultiLineString(stringTokens, fullSpan);
  1182→    return new MultiLineStringLiteralExpr(parts, start.span, end, fullSpan);
  1183→  }
