  1185→  private List<StringPart> validateMultiLineString(List<TempNode> nodes, Span span) {
  1186→    var firstNode = nodes.isEmpty() ? null : nodes.get(0);
  1187→    if (firstNode == null
  1188→        || firstNode.token == null
  1189→        || firstNode.token.token != Token.STRING_NEWLINE) {
  1190→      var errorSpan = firstNode == null ? span : firstNode.span();
  1191→      throw new ParserError(ErrorMessages.create("stringContentMustBeginOnNewLine"), errorSpan);
  1192→    }
  1193→    // only contains a newline
  1194→    if (nodes.size() == 1) {
  1195→      return List.of(new StringChars("", firstNode.span()));
  1196→    }
  1197→    var indent = getCommonIndent(nodes, span);
  1198→    return renderString(nodes, indent);
  1199→  }
