  1201→  @SuppressWarnings("DataFlowIssue")
  1202→  private List<StringPart> renderString(List<TempNode> nodes, String commonIndent) {
  1203→    var parts = new ArrayList<StringPart>();
  1204→    var builder = new StringBuilder();
  1205→    var endOffset = nodes.get(nodes.size() - 1).token.token == Token.STRING_NEWLINE ? 1 : 2;
  1206→    var isNewLine = true;
  1207→    Span start = null;
  1208→    Span end = null;
  1209→    for (var i = 1; i < nodes.size() - endOffset; i++) {
  1210→      var node = nodes.get(i);
  1211→      if (node.node != null) {
  1212→        if (!builder.isEmpty()) {
  1213→          parts.add(new StringChars(builder.toString(), start.endWith(end)));
  1214→          builder = new StringBuilder();
  1215→          start = null;
  1216→        }
  1217→        parts.add(node.node);
  1218→      } else {
  1219→        var token = node.token;
  1220→        assert token != null;
  1221→        if (start == null) {
  1222→          start = token.span;
  1223→        }
  1224→        end = token.span;
  1225→        switch (token.token) {
  1226→          case STRING_NEWLINE -> {
  1227→            builder.append('\n');
  1228→            isNewLine = true;
  1229→          }
  1230→          case STRING_PART -> {
  1231→            var text = token.text(lexer);
  1232→            if (isNewLine) {
  1233→              if (text.startsWith(commonIndent)) {
  1234→                builder.append(text, commonIndent.length(), text.length());
  1235→              } else {
  1236→                var actualIndent = getLeadingIndentCount(text);
  1237→                var textSpan = token.span.move(actualIndent).grow(-actualIndent);
  1238→                throw new ParserError(
  1239→                    ErrorMessages.create("stringIndentationMustMatchLastLine"), textSpan);
  1240→              }
  1241→            } else {
  1242→              builder.append(text);
  1243→            }
  1244→            isNewLine = false;
  1245→          }
  1246→          default -> {
  1247→            if (isNewLine && !commonIndent.isEmpty()) {
  1248→              throw new ParserError(
  1249→                  ErrorMessages.create("stringIndentationMustMatchLastLine"), token.span);
  1250→            }
  1251→            builder.append(getEscapeText(token));
  1252→            isNewLine = false;
  1253→          }
  1254→        }
  1255→      }
  1256→    }
  1257→    if (!builder.isEmpty()) {
  1258→      parts.add(new StringChars(builder.toString(), start.endWith(end)));
  1259→    }
  1260→    return parts;
  1261→  }
