  1264→  private Expr parseFunctionLiteralOrParenthesized(Span start) {
  1265→    var identifier = parseIdentifier();
  1266→    return switch (lookahead) {
  1267→      case COMMA -> {
  1268→        next();
  1269→        var params = new ArrayList<Parameter>();
  1270→        params.add(new TypedIdentifier(identifier, null, identifier.span()));
  1271→        params.addAll(parseListOfParameter(Token.COMMA));
  1272→        var endParen = expect(Token.RPAREN, "unexpectedToken2", ",", ")").span;
  1273→        var paramList = new ParameterList(params, start.endWith(endParen));
  1274→        expect(Token.ARROW, "unexpectedToken", "->");
  1275→        var expr = parseExpr();
  1276→        yield new FunctionLiteralExpr(paramList, expr, start.endWith(expr.span()));
  1277→      }
  1278→      case COLON -> {
  1279→        var typeAnnotation = parseTypeAnnotation();
  1280→        var params = new ArrayList<Parameter>();
  1281→        params.add(
  1282→            new TypedIdentifier(
  1283→                identifier, typeAnnotation, identifier.span().endWith(typeAnnotation.span())));
  1284→        if (lookahead == Token.COMMA) {
  1285→          next();
  1286→          params.addAll(parseListOfParameter(Token.COMMA));
  1287→        }
  1288→        var endParen = expect(Token.RPAREN, "unexpectedToken2", ",", ")").span;
  1289→        var paramList = new ParameterList(params, start.endWith(endParen));
  1290→        expect(Token.ARROW, "unexpectedToken", "->");
  1291→        var expr = parseExpr(")");
  1292→        yield new FunctionLiteralExpr(paramList, expr, start.endWith(expr.span()));
  1293→      }
  1294→      case RPAREN -> {
  1295→        // still not sure
  1296→        var end = next().span;
  1297→        if (lookahead == Token.ARROW) {
  1298→          next();
  1299→          var expr = parseExpr();
  1300→          var params = new ArrayList<Parameter>();
  1301→          params.add(new TypedIdentifier(identifier, null, identifier.span()));
  1302→          var paramList = new ParameterList(params, start.endWith(end));
  1303→          yield new FunctionLiteralExpr(paramList, expr, start.endWith(expr.span()));
  1304→        } else {
  1305→          var exp = new UnqualifiedAccessExpr(identifier, null, identifier.span());
  1306→          yield new ParenthesizedExpr(exp, start.endWith(end));
  1307→        }
  1308→      }
  1309→      default -> {
  1310→        // this is an expression
  1311→        backtrack();
  1312→        var expr = parseExpr(")");
  1313→        var end = expect(Token.RPAREN, "unexpectedToken", ")").span;
  1314→        yield new ParenthesizedExpr(expr, start.endWith(end));
  1315→      }
  1316→    };
  1317→  }
