  1333→  private Type parseType(@Nullable String expectation) {
  1334→    var defaultIndex = -1;
  1335→    Span start = null;
  1336→    if (lookahead == Token.STAR) {
  1337→      defaultIndex = 0;
  1338→      start = next().span;
  1339→    }
  1340→    var first = parseTypeAtom(expectation);
  1341→    if (start == null) {
  1342→      start = first.span();
  1343→    }
  1344→
  1345→    if (lookahead != Token.UNION) {
  1346→      if (defaultIndex == 0) {
  1347→        throw new ParserError(ErrorMessages.create("notAUnion"), start.endWith(first.span()));
  1348→      }
  1349→      return first;
  1350→    }
  1351→
  1352→    var types = new ArrayList<Type>();
  1353→    types.add(first);
  1354→    var end = start;
  1355→    var i = 1;
  1356→    while (lookahead == Token.UNION) {
  1357→      next();
  1358→      if (lookahead == Token.STAR) {
  1359→        if (defaultIndex != -1) {
  1360→          throw parserError("multipleUnionDefaults");
  1361→        }
  1362→        defaultIndex = i;
  1363→        next();
  1364→      }
  1365→      var type = parseTypeAtom(expectation);
  1366→      types.add(type);
  1367→      end = type.span();
  1368→      i++;
  1369→    }
  1370→    return new Type.UnionType(types, defaultIndex, start.endWith(end));
  1371→  }
