  1373→  private Type parseTypeAtom(@Nullable String expectation) {
  1374→    Type typ;
  1375→    switch (lookahead) {
  1376→      case UNKNOWN -> typ = new Type.UnknownType(next().span);
  1377→      case NOTHING -> typ = new Type.NothingType(next().span);
  1378→      case MODULE -> typ = new Type.ModuleType(next().span);
  1379→      case LPAREN -> {
  1380→        var tk = next();
  1381→        var children = new ArrayList<Node>();
  1382→        Span end;
  1383→        if (lookahead == Token.RPAREN) {
  1384→          end = next().span;
  1385→        } else {
  1386→          children.addAll(parseListOf(Token.COMMA, () -> parseType(")")));
  1387→          end = expect(Token.RPAREN, "unexpectedToken2", ",", ")").span;
  1388→        }
  1389→        if (lookahead == Token.ARROW || children.size() > 1) {
  1390→          expect(Token.ARROW, "unexpectedToken", "->");
  1391→          var ret = parseType(expectation);
  1392→          children.add(ret);
  1393→          typ = new Type.FunctionType(children, tk.span.endWith(ret.span()));
  1394→        } else {
  1395→          typ = new ParenthesizedType((Type) children.get(0), tk.span.endWith(end));
  1396→        }
  1397→      }
  1398→      case IDENTIFIER -> {
  1399→        var start = spanLookahead;
  1400→        var name = parseQualifiedIdentifier();
  1401→        var end = name.span();
  1402→        TypeArgumentList typeArgumentList = null;
  1403→        if (lookahead == Token.LT) {
  1404→          typeArgumentList = parseTypeArgumentList();
  1405→          end = typeArgumentList.span();
  1406→        }
  1407→        typ = new DeclaredType(name, typeArgumentList, start.endWith(end));
  1408→      }
  1409→      case STRING_START -> {
  1410→        var str = parseStringConstant();
  1411→        typ = new StringConstantType(str, str.span());
  1412→      }
  1413→      default -> {
  1414→        var text = _lookahead.text(lexer);
  1415→        if (expectation != null) {
  1416→          throw parserError("unexpectedTokenForType2", text, expectation);
  1417→        }
  1418→        throw parserError("unexpectedTokenForType", text);
  1419→      }
  1420→    }
  1421→
  1422→    if (typ instanceof Type.FunctionType) return typ;
  1423→    return parseTypeEnd(typ);
