  1426→  private Type parseTypeEnd(Type type) {
  1427→    // nullable types
  1428→    if (lookahead == Token.QUESTION) {
  1429→      var end = spanLookahead;
  1430→      next();
  1431→      var res = new Type.NullableType(type, type.span().endWith(end));
  1432→      return parseTypeEnd(res);
  1433→    }
  1434→    // constrained types: have to start in the same line as the type
  1435→    if (lookahead == Token.LPAREN && !precededBySemicolon && _lookahead.newLinesBetween == 0) {
  1436→      next();
  1437→      var constraints = parseListOf(Token.COMMA, () -> parseExpr(")"));
  1438→      var end = expect(Token.RPAREN, "unexpectedToken2", ",", ")").span;
  1439→      var children = new ArrayList<Node>(constraints.size() + 1);
  1440→      children.add(type);
  1441→      children.addAll(constraints);
  1442→      var res = new Type.ConstrainedType(children, type.span().endWith(end));
  1443→      return parseTypeEnd(res);
  1444→    }
  1445→    return type;
  1446→  }
