  1587→    while (lookahead != Token.STRING_END) {
  1588→      switch (lookahead) {
  1589→        case STRING_PART -> builder.append(next().text(lexer));
  1590→        case STRING_ESCAPE_NEWLINE -> {
  1591→          next();
  1592→          builder.append('\n');
  1593→        }
  1594→        case STRING_ESCAPE_TAB -> {
  1595→          next();
  1596→          builder.append('\t');
  1597→        }
  1598→        case STRING_ESCAPE_QUOTE -> {
  1599→          next();
  1600→          builder.append('"');
  1601→        }
  1602→        case STRING_ESCAPE_BACKSLASH -> {
  1603→          next();
  1604→          builder.append('\\');
  1605→        }
  1606→        case STRING_ESCAPE_RETURN -> {
  1607→          next();
  1608→          builder.append('\r');
  1609→        }
  1610→        case STRING_ESCAPE_UNICODE -> builder.append(parseUnicodeEscape(next()));
  1611→        case EOF -> {
  1612→          var delimiter = new StringBuilder(startTk.text(lexer)).reverse().toString();
  1613→          throw parserError("missingDelimiter", delimiter);
  1614→        }
  1615→        case INTERPOLATION_START -> throw parserError("interpolationInConstant");
  1616→        // the lexer makes sure we only get the above tokens inside a string
  1617→        default -> throw new RuntimeException("Unreacheable code");
  1618→      }
  1619→    }
  1620→    var end = next().span;
  1621→    return new StringConstant(builder.toString(), start.endWith(end));
  1622→  }
  1623→
  1624→  private String getEscapeText(FullToken tk) {
  1625→    return switch (tk.token) {
  1626→      case STRING_ESCAPE_NEWLINE -> "\n";
  1627→      case STRING_ESCAPE_QUOTE -> "\"";
  1628→      case STRING_ESCAPE_BACKSLASH -> "\\";
  1629→      case STRING_ESCAPE_TAB -> "\t";
  1630→      case STRING_ESCAPE_RETURN -> "\r";
  1631→      case STRING_ESCAPE_UNICODE -> parseUnicodeEscape(tk);
  1632→      default -> throw new RuntimeException("Unreacheable code");
  1633→    };
  1634→  }
  1635→
  1636→  private String parseUnicodeEscape(FullToken tk) {
  1637→    var text = tk.text(lexer);
  1638→    var lastIndex = text.length() - 1;
  1639→    var startIndex = text.indexOf('{', 2);
  1640→    try {
  1641→      var codepoint = Integer.parseInt(text.substring(startIndex + 1, lastIndex), 16);
  1642→      return Character.toString(codepoint);
  1643→    } catch (NumberFormatException e) {
  1644→      throw new ParserError(
  1645→          ErrorMessages.create("invalidUnicodeEscapeSequence", text, text.substring(0, startIndex)),
  1646→          tk.span);
  1647→    }
  1648→  }
  1649→
  1650→  private String getCommonIndent(List<TempNode> nodes, Span span) {
  1651→    var lastNode = nodes.get(nodes.size() - 1);
  1652→    if (lastNode.token == null) {
  1653→      throw new ParserError(
  1654→          ErrorMessages.create("closingStringDelimiterMustBeginOnNewLine"), lastNode.span());
  1655→    }
  1656→    if (lastNode.token.token == Token.STRING_NEWLINE) return "";
  1657→    var beforeLast = nodes.get(nodes.size() - 2);
  1658→    if (beforeLast.token != null && beforeLast.token.token == Token.STRING_NEWLINE) {
  1659→      var indent = getTrailingIndent(lastNode);
  1660→      if (indent != null) {
  1661→        return indent;
  1662→      }
  1663→    }
  1664→    throw new ParserError(ErrorMessages.create("closingStringDelimiterMustBeginOnNewLine"), span);
  1665→  }
  1666→
  1667→  private @Nullable String getTrailingIndent(TempNode node) {
  1668→    var token = node.token;
  1669→    if (token == null || token.token != Token.STRING_PART) return null;
  1670→    var text = token.text(lexer);
  1671→    for (var i = 0; i < text.length(); i++) {
  1672→      var ch = text.charAt(i);
  1673→      if (ch != ' ' && ch != '\t') return null;
  1674→    }
  1675→    return text;
  1676→  }
  1677→
  1678→  private int getLeadingIndentCount(String text) {
  1679→    if (text.isEmpty()) return 0;
  1680→    for (var i = 0; i < text.length(); i++) {
  1681→      var ch = text.charAt(i);
  1682→      if (ch != ' ' && ch != '\t') {
  1683→        return i;
  1684→      }
  1685→    }
  1686→    return text.length();
  1687→  }
  1688→
  1689→  private record TempNode(
  1690→      @Nullable FullToken token, @Nullable StringPart.StringInterpolation node) {
  1691→    Span span() {
  1692→      if (token != null) return token.span;
  1693→      assert node != null;
  1694→      return node.span();
  1695→    }
  1696→  }
  1697→
  1698→  private FullToken expect(Token type, String errorKey, Object... messageArgs) {
  1699→    if (lookahead != type) {
  1700→      var span = spanLookahead;
  1701→      if (lookahead == Token.EOF || _lookahead.newLinesBetween > 0) {
  1702→        // don't point at the EOF or the next line, but at the end of the last token
  1703→        span = prev.span.stopSpan().move(1);
  1704→      }
  1705→      var args = messageArgs;
  1706→      if (errorKey.startsWith("unexpectedToken")) {
  1707→        args = new Object[messageArgs.length + 1];
  1708→        args[0] = lookahead == Token.EOF ? "EOF" : _lookahead.text(lexer);
  1709→        System.arraycopy(messageArgs, 0, args, 1, messageArgs.length);
  1710→      }
  1711→      throw new ParserError(ErrorMessages.create(errorKey, args), span);
  1712→    }
  1713→    return next();
  1714→  }
  1715→
  1716→  private <T> List<T> parseListOf(Token separator, Supplier<T> parser) {
  1717→    var res = new ArrayList<T>();
  1718→    res.add(parser.get());
  1719→    while (lookahead == separator) {
  1720→      next();
  1721→      res.add(parser.get());
  1722→    }
  1723→    return res;
  1724→  }
  1725→
  1726→  private List<Parameter> parseListOfParameter(Token separator) {
  1727→    var res = new ArrayList<Parameter>();
  1728→    res.add(parseParameter());
  1729→    while (lookahead == separator) {
  1730→      next();
  1731→      res.add(parseParameter());
  1732→    }
  1733→    return res;
  1734→  }
  1735→
  1736→  private ParserError parserError(String messageKey, Object... args) {
  1737→    return new ParserError(ErrorMessages.create(messageKey, args), spanLookahead);
  1738→  }
  1739→
  1740→  private record MemberHeader(
  1741→      @Nullable DocComment docComment, List<Annotation> annotations, List<Modifier> modifiers) {
  1742→    boolean isNotEmpty() {
  1743→      return !(docComment == null && annotations.isEmpty() && modifiers.isEmpty());
  1744→    }
  1745→
  1746→    @SuppressWarnings("DataFlowIssue")
  1747→    @Nullable
  1748→    Span span() {
  1749→      return span(null);
  1750→    }
  1751→
  1752→    Span span(Span or) {
  1753→      if (docComment != null) {
  1754→        return docComment.span();
  1755→      }
  1756→      if (!annotations().isEmpty()) {
  1757→        return annotations.get(0).span();
  1758→      }
  1759→      if (!modifiers().isEmpty()) {
  1760→        return modifiers.get(0).span();
  1761→      }
  1762→      return or;
  1763→    }
  1764→
  1765→    Span modifierSpan(Span or) {
  1766→      if (!modifiers.isEmpty()) {
  1767→        return modifiers.get(0).span();
  1768→      }
  1769→      return or;
  1770→    }
  1771→  }
  1772→
  1773→  private FullToken next() {
  1774→    if (backtracking) {
  1775→      backtracking = false;
  1776→      lookahead = _lookahead.token;
  1777→      spanLookahead = _lookahead.span;
  1778→      return prev;
  1779→    }
  1780→    prev = _lookahead;
  1781→    _lookahead = forceNext();
  1782→    lookahead = _lookahead.token;
  1783→    spanLookahead = _lookahead.span;
  1784→    return prev;
  1785→  }
  1786→
  1787→  private FullToken forceNext() {
  1788→    var tk = lexer.next();
  1789→    precededBySemicolon = false;
  1790→    while (tk == Token.LINE_COMMENT
  1791→        || tk == Token.BLOCK_COMMENT
  1792→        || tk == Token.SEMICOLON
  1793→        || tk == Token.SHEBANG) {
  1794→      precededBySemicolon = precededBySemicolon || tk == Token.SEMICOLON;
  1795→      tk = lexer.next();
  1796→    }
  1797→    return new FullToken(tk, lexer.span(), lexer.newLinesBetween);
  1798→  }
  1799→
  1800→  // Like next, but don't ignore comments
  1801→  private FullToken nextComment() {
  1802→    prev = _lookahead;
  1803→    _lookahead = forceNextComment();
  1804→    lookahead = _lookahead.token;
  1805→    spanLookahead = _lookahead.span;
  1806→    return prev;
  1807→  }
  1808→
  1809→  private FullToken forceNextComment() {
  1810→    var tk = lexer.next();
  1811→    precededBySemicolon = false;
  1812→    while (tk == Token.SEMICOLON) {
  1813→      precededBySemicolon = true;
  1814→      tk = lexer.next();
  1815→    }
  1816→    return new FullToken(tk, lexer.span(), lexer.newLinesBetween);
  1817→  }
  1818→
  1819→  /**
  1820→   * Backtrack to the previous token.
  1821→   *
  1822→   * <p>Can only backtrack one token.
  1823→   */
  1824→  private void backtrack() {
  1825→    assert !backtracking;
  1826→    lookahead = prev.token;
  1827→    spanLookahead = prev.span;
  1828→    backtracking = true;
  1829→  }
  1830→
  1831→  private void ensureEmptyHeaders(MemberHeader header, String messageArg) {
  1832→    if (header.isNotEmpty()) {
  1833→      throw new ParserError(
  1834→          ErrorMessages.create("wrongHeaders", messageArg), header.span(spanLookahead));
  1835→    }
  1836→  }
  1837→
  1838→  private record FullToken(Token token, Span span, int newLinesBetween) {
  1839→    String text(Lexer lexer) {
  1840→      return lexer.textFor(span.charIndex(), span.length());
  1841→    }
  1842→  }
  1843→}
  1844→

