class ShebangTest {
  private val evaluator = Evaluator.preconfigured()

  @Test
  fun `shebang is ignored only at start of file`() {
    val module =
      evaluator.evaluate(
        ModuleSource.text(
          """
          #!/usr/local/bin/pkl
          x = 1
        """
            .trimIndent()
        )
      )

    assertThat(module.properties["x"]).isEqualTo(1L)
  }

  @Test
  fun `shebang not at start of file is a parse error`() {
    val moduleSource =
      ModuleSource.text(
        """
        x = 1

        #!/usr/local/bin/pkl
        y = 2
        """.trimIndent()
      )

    val error = org.assertj.core.api.Assertions.catchThrowable { evaluator.evaluate(moduleSource) }

    assertThat(error).isNotNull
    // parser should not accept a shebang after other content
    assertThat(error).hasMessageContaining("#!/usr/local/bin/pkl")
  }
}

